// Generated by Claude Opus 4.6

import {
  Alert,
  Breadcrumb,
  BreadcrumbItem,
  Button,
  Content,
  ContentVariants,
  EmptyState,
  EmptyStateBody,
  EmptyStateVariant,
  Flex,
  FlexItem,
  PageSection,
  Spinner,
  Split,
  SplitItem,
  Stack,
  StackItem,
  Toolbar,
  ToolbarContent,
  ToolbarItem,
} from '@patternfly/react-core';
import { RocketIcon } from '@patternfly/react-icons';
import React from 'react';
import { NavigateFunction } from 'react-router-dom';

import AgentPodEvents from '@/components/AgentPodEvents';
import AgentTerminal from '@/components/AgentTerminal';
import { DevfileEditor } from '@/components/DevfileEditor';
import EditorTools from '@/components/EditorTools';
import Head from '@/components/Head';
import TerminalTools from '@/components/TerminalTools';
import { DropdownActions } from '@/pages/DevfileDetails/DropdownActions';
import styles from '@/pages/DevfileDetails/index.module.css';
import { DevfileSchema } from '@/services/backend-client/devfileSchemaApi';
import { AgentPodStatus, LocalDevfile } from '@/store/LocalDevfiles';

interface Props {
  devfile: LocalDevfile;
  devfileSchema: DevfileSchema | undefined;
  namespace: string;
  navigate: NavigateFunction;
  onSave: (id: string, content: string) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  onStartAgent: () => Promise<void>;
  onStopAgent: () => void;
  agentPodStatus: AgentPodStatus | undefined;
  agentTerminalUrl: string | undefined;
  isDarkTheme: boolean;
  agentEnabled: boolean;
  agentInitCommand?: string;
  agentInstanceId?: string;
}

interface State {
  editorContent: string;
  isSaved: boolean;
  isStartingAgent: boolean;
  saveError: string | undefined;
  agentError: string | undefined;
  hasValidationError: boolean;
  isEditorExpanded: boolean;
  isTerminalExpanded: boolean;
}

export default class DevfileDetails extends React.PureComponent<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      editorContent: props.devfile.content,
      isSaved: true,
      isStartingAgent: false,
      saveError: undefined,
      agentError: undefined,
      hasValidationError: false,
      isEditorExpanded: false,
      isTerminalExpanded: false,
    };
  }

  componentDidUpdate(prevProps: Props) {
    if (prevProps.devfile.id !== this.props.devfile.id) {
      this.setState({
        editorContent: this.props.devfile.content,
        isSaved: true,
        isStartingAgent: false,
        saveError: undefined,
        agentError: undefined,
        hasValidationError: false,
      });
    } else if (prevProps.devfile.content !== this.props.devfile.content) {
      this.setState({
        editorContent: this.props.devfile.content,
        isSaved: true,
      });
    }
  }

  private handleEditorChange = (value: string) => {
    this.setState({
      editorContent: value,
      isSaved: false,
    });
  };

  private handleValidation = (errorMessage: string) => {
    this.setState({ hasValidationError: errorMessage.length > 0 });
  };

  private handleSave = () => {
    const { devfile, onSave } = this.props;
    const { editorContent } = this.state;
    try {
      onSave(devfile.id, editorContent);
      this.setState({ isSaved: true, saveError: undefined });
    } catch (e) {
      const message = e instanceof Error ? e.message : 'Save failed';
      this.setState({ saveError: message });
    }
  };

  private handleRefresh = () => {
    this.setState({
      editorContent: this.props.devfile.content,
      isSaved: true,
      saveError: undefined,
    });
    this.props.onRefresh();
  };

  private handleStartAgent = async () => {
    this.setState({ isStartingAgent: true, agentError: undefined });
    try {
      await this.props.onStartAgent();
    } catch (e) {
      const message = e instanceof Error ? e.message : 'Failed to start agent';
      this.setState({ agentError: message });
    } finally {
      this.setState({ isStartingAgent: false });
    }
  };

  private handleEditorExpand = (isExpanded: boolean) => {
    this.setState({ isEditorExpanded: isExpanded });
  };

  private handleTerminalExpandToggle = () => {
    this.setState(prev => ({ isTerminalExpanded: !prev.isTerminalExpanded }));
  };

  private buildRawDevfileUrl(): string {
    const { devfile, namespace } = this.props;
    return `${window.location.origin}/dashboard/api/devfiles/namespace/${namespace}/${devfile.id}/raw`;
  }

  private handleCopyLink = () => {
    const url = this.buildRawDevfileUrl();
    navigator.clipboard.writeText(url);
  };

  private handleDownload = () => {
    const { devfile } = this.props;
    const { editorContent } = this.state;
    const blob = new Blob([editorContent], { type: 'application/x-yaml' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${devfile.name}.devfile.yaml`;
    a.click();
    URL.revokeObjectURL(url);
  };

  private handleCreateWorkspace = () => {
    const { navigate } = this.props;
    const devfileUrl = this.buildRawDevfileUrl();
    navigate({
      pathname: '/create-workspace',
      search: `?url=${encodeURIComponent(devfileUrl)}`,
    });
  };

  private handleDelete = () => {
    const { devfile, onDelete } = this.props;
    onDelete(devfile.id);
  };

  private renderStartButton(): React.ReactElement {
    const { isStartingAgent } = this.state;
    return (
      <Button
        variant="primary"
        isLoading={isStartingAgent}
        isDisabled={isStartingAgent}
        onClick={this.handleStartAgent}
      >
        {isStartingAgent ? 'Starting...' : 'Start Agent'}
      </Button>
    );
  }

  private renderStopButton(): React.ReactElement {
    return (
      <Button variant="secondary" isDanger onClick={this.props.onStopAgent}>
        Stop
      </Button>
    );
  }

  private renderAgentPanel(): React.ReactElement {
    const { agentPodStatus, agentTerminalUrl } = this.props;
    const { agentError } = this.state;

    if (agentPodStatus) {
      const phase = agentPodStatus.phase;
      const isRunning = phase === 'Running' && agentPodStatus.ready;
      const isFailed = phase === 'Failed' || phase === 'Succeeded' || phase === 'Unknown';
      const isPending = phase === 'Pending';

      if (isRunning && agentTerminalUrl) {
        const agentDisplayId = this.props.agentInstanceId || agentPodStatus.agentId;
        return (
          <div className={styles.agentPanelTerminal}>
            <div className={styles.terminalToolbar}>
              <span className={styles.agentIdLabel}>{agentDisplayId}</span>
              <TerminalTools
                isExpanded={this.state.isTerminalExpanded}
                onToggleExpand={this.handleTerminalExpandToggle}
              />
            </div>
            <AgentTerminal
              terminalUrl={agentTerminalUrl}
              namespace={this.props.namespace}
              devfileName={this.props.devfile.name}
              isDarkTheme={this.props.isDarkTheme}
              initCommand={this.props.agentInitCommand}
            />
          </div>
        );
      }

      if (isFailed) {
        return (
          <div className={styles.agentPanelEvents}>
            <Stack hasGutter>
              <StackItem>
                <Alert
                  variant="danger"
                  isInline
                  title="Agent failed"
                  style={{ marginBottom: '8px' }}
                >
                  Agent pod status: {phase}
                </Alert>
              </StackItem>
              <StackItem>{this.renderStartButton()}</StackItem>
              <StackItem>
                <AgentPodEvents podName={agentPodStatus.name} />
              </StackItem>
            </Stack>
          </div>
        );
      }

      if (isPending || (phase === 'Running' && !agentPodStatus.ready)) {
        return (
          <div className={styles.agentPanelEvents}>
            <Stack hasGutter>
              <StackItem>
                <Flex alignItems={{ default: 'alignItemsCenter' }}>
                  <FlexItem>
                    <Spinner size="md" />
                  </FlexItem>
                  <FlexItem>
                    <Content component={ContentVariants.p}>Starting agent...</Content>
                  </FlexItem>
                  <FlexItem align={{ default: 'alignRight' }}>{this.renderStopButton()}</FlexItem>
                </Flex>
              </StackItem>
              <StackItem>
                <AgentPodEvents podName={agentPodStatus.name} />
              </StackItem>
            </Stack>
          </div>
        );
      }
    }

    return (
      <div className={`${styles.agentEmptyState} ${styles.agentPanelEmpty}`}>
        <div>
          {agentError && (
            <Alert variant="danger" isInline title="Agent error" style={{ marginBottom: '16px' }}>
              {agentError}
            </Alert>
          )}
          <EmptyState headingLevel="h3" titleText="AI Agent" variant={EmptyStateVariant.sm}>
            <EmptyStateBody>Start an AI agent to get help building your devfile.</EmptyStateBody>
            <div className={styles.spacer16} />
            {this.renderStartButton()}
          </EmptyState>
        </div>
      </div>
    );
  }

  render(): React.ReactElement {
    const { devfile, agentPodStatus, agentTerminalUrl, agentEnabled } = this.props;
    const { editorContent, isSaved, saveError, hasValidationError, isTerminalExpanded } =
      this.state;
    const isAgentConnected =
      agentPodStatus?.phase === 'Running' &&
      agentPodStatus?.ready === true &&
      agentTerminalUrl !== undefined;

    return (
      <React.Fragment>
        <Head pageName={`Devfile: ${devfile.name}`} />
        <PageSection>
          <Stack hasGutter>
            <StackItem>
              <Breadcrumb>
                <BreadcrumbItem to="#/devfiles">Devfiles</BreadcrumbItem>
                <BreadcrumbItem isActive>{devfile.name}</BreadcrumbItem>
              </Breadcrumb>
            </StackItem>
            <StackItem>
              <Flex>
                <FlexItem alignSelf={{ default: 'alignSelfCenter' }}>
                  <Content>
                    <Content component={ContentVariants.h1}>{devfile.name}</Content>
                  </Content>
                </FlexItem>
                <FlexItem align={{ default: 'alignRight' }}>
                  <DropdownActions
                    onCopyLink={this.handleCopyLink}
                    onDownload={this.handleDownload}
                    onDelete={this.handleDelete}
                  />
                </FlexItem>
              </Flex>
            </StackItem>
          </Stack>
        </PageSection>
        <PageSection isFilled style={{ overflow: 'hidden' }}>
          <Split hasGutter style={{ height: '100%' }}>
            {!(isAgentConnected && isTerminalExpanded) && (
              <SplitItem isFilled className={styles.editorPanel}>
                {saveError && (
                  <Alert
                    variant="danger"
                    isInline
                    title="Save failed"
                    style={{ marginBottom: '8px' }}
                  >
                    {saveError}
                  </Alert>
                )}
                <EditorTools
                  contentText={editorContent}
                  workspaceName={devfile.name}
                  handleExpand={this.handleEditorExpand}
                />
                <div className={styles.editorContainer}>
                  <DevfileEditor
                    id="devfile-editor-id"
                    value={editorContent}
                    schema={this.props.devfileSchema}
                    onChange={this.handleEditorChange}
                    onValidation={this.handleValidation}
                  />
                </div>
                <div className={styles.spacer8} />
                <Toolbar className={styles.editorToolbar}>
                  <ToolbarContent className={styles.editorToolbarContent}>
                    <ToolbarItem>
                      <Button variant="secondary" onClick={this.handleRefresh}>
                        Refresh
                      </Button>
                    </ToolbarItem>
                    <ToolbarItem>
                      <Button
                        variant="primary"
                        onClick={this.handleSave}
                        isDisabled={isSaved || hasValidationError}
                      >
                        Save
                      </Button>
                    </ToolbarItem>
                    <ToolbarItem>
                      <Button
                        variant="secondary"
                        icon={<RocketIcon />}
                        iconPosition="left"
                        isDisabled={!isSaved || hasValidationError}
                        onClick={this.handleCreateWorkspace}
                      >
                        Create Workspace
                      </Button>
                    </ToolbarItem>
                  </ToolbarContent>
                </Toolbar>
              </SplitItem>
            )}

            {agentEnabled && (
              <SplitItem
                isFilled={isAgentConnected && isTerminalExpanded}
                className={isAgentConnected ? styles.agentPanel : undefined}
                style={{
                  width:
                    isAgentConnected && isTerminalExpanded
                      ? '100%'
                      : isAgentConnected
                        ? '50%'
                        : '500px',
                  minWidth: '350px',
                  transition: 'width 0.3s ease',
                }}
              >
                {this.renderAgentPanel()}
                {isAgentConnected && (
                  <Toolbar className={styles.editorToolbar}>
                    <ToolbarContent>
                      <ToolbarItem>{this.renderStopButton()}</ToolbarItem>
                    </ToolbarContent>
                  </Toolbar>
                )}
              </SplitItem>
            )}
          </Split>
        </PageSection>
      </React.Fragment>
    );
  }
}
